// tool-registry/tools/document-write/contract.json
// Version: 2.1.0  Owner: @deiva/docs-team
// Required approvers: @deiva/ai-platform  @deiva/safety-reviewers
{
  "name": "document_write",
  "description": "Write content to a user-owned document. Only the document owner's documents are accessible. Maximum content size 100KB per call.",
  "input_schema": {
    "type": "object",
    "properties": {
      "document_id": {
        "type": "string",
        "description": "The ID of the document to write. Must belong to the authenticated user."
      },
      "content": {
        "type": "string",
        "maxLength": 102400,
        "description": "The content to write. Replaces the existing document body."
      },
      "append": {
        "type": "boolean",
        "default": false,
        "description": "If true, append content rather than replace. Still subject to maxLength per call."
      }
    },
    "required": ["document_id", "content"],
    "additionalProperties": false
  }
}

// --- Safety Reviewer Checklist (filled in at PR review time) ---
// [ ] Does the tool perform a write operation?
//     Yes — safety review is mandatory.
// [ ] Is the operation scoped to the authenticated user's own data?
//     Yes — document_id is server-validated against session ownership.
// [ ] Does the schema include a size constraint?
//     Yes — maxLength: 102400 on content; additionalProperties: false.
// [ ] Can this tool be used to exfiltrate data to an external system?
//     No — writes only to internal document store.
// [ ] Is there an audit log for calls to this tool?
//     Yes — document write events logged to audit trail with user_id and agent_session_id.
// [ ] Has the docs-team confirmed SLA (p99 < 500ms, error rate < 0.1%)?
//     Yes — confirmed in PR comment.
